import React, { useEffect, useState } from 'react';

const Navbar = () => {
  const [theme, setTheme] = useState('light');

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === 'light' ? 'dark' : 'light'));
  };

  return (
    <nav style={styles.nav}>
      <h1 style={styles.logo}>MyPortfolio</h1>
      <ul style={styles.navLinks}>
        <li><a href="#home">Home</a></li>
        <li><a href="#about">About</a></li>
        <li><a href="#projects">Projects</a></li>
        <li><a href="#contact">Contact</a></li>
        <li><button onClick={toggleTheme} style={styles.toggleBtn}>
          {theme === 'light' ? '🌙' : '☀️'}
        </button></li>
      </ul>
    </nav>
  );
};

const styles = {
  nav: {
    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
    padding: '1rem 2rem', backgroundColor: 'var(--primary-bg)', color: 'var(--primary-text)'
  },
  logo: {
    fontSize: '1.5rem'
  },
  navLinks: {
    display: 'flex', gap: '1rem', listStyle: 'none', alignItems: 'center'
  },
  toggleBtn: {
    background: 'none', border: 'none', fontSize: '1.2rem', cursor: 'pointer'
  }
};

export default Navbar;
